final:
module counter(
    input clk,
    input reset,
    input up,
    output reg [3:0] count);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
    if (reset)
        count <= 0;
    else if (up)
        count <= count + 1;
    else
        count <= count - 1;

endmodule
